// 11. LOS ANGELES FILM FESTIVAL / LALIFF
export const LAFilmFestIcon = (props: FestivalIconProps) => {
  // As posições matemáticas exatas do rolo de filme que você encontrou!
  const holes = [3.8, 23, 42.1, 61.3, 80.4, 99.6, 118.7, 137.9, 157, 176.2, 195.3];

  return (
    <svg viewBox="0 0 210 100" fill="currentColor" {...props}>
      {/* Furos Superiores do Rolo de Filme */}
      <g transform="translate(0, 10)">
        {holes.map((x, i) => (
          <rect key={`top-${i}`} x={x} y="0" width="11.3" height="11.1" rx="2" />
        ))}
      </g>
      
      {/* O Letreiro 100% Vetorial (Substituindo a imagem PNG pesada) */}
      <text x="50%" y="54%" dominantBaseline="middle" textAnchor="middle" fontSize="32" fontFamily="Inter, sans-serif" fontWeight="900" letterSpacing="0.1em">LALIFF</text>
      
      {/* Furos Inferiores (Com o furo vermelho característico na posição 6) */}
      <g transform="translate(0, 77)">
        {holes.map((x, i) => (
          <rect 
            key={`bot-${i}`} 
            x={x} 
            y="0" 
            width="11.3" 
            height="11.1" 
            rx="2" 
            fill={i === 6 ? "#ed2024" : "currentColor"} 
          />
        ))}
      </g>
    </svg>
  );
};


