// ============================================================================
// DICIONÁRIO E MOTOR DE CURADORIA (TIERS)
// ============================================================================
export interface FestivalData {
  label: string;
  Icon: React.ElementType;
  weight: number; // S+ = 100 | S = 90 | A = 80 | B = 70 | C = 10
}

export const getFestivalDictionary = (festivalName: string): FestivalData => {

    if (!festivalName) {
        return { label: "SELEÇÃO OFICIAL", Icon: GenericLaurelIcon, weight: 10 };
    }

  const name = festivalName.toUpperCase();

  // --- TIER S+ (Santíssima Trindade Europeia - Peso 100) ---
  if (name.includes("CANNES") || name.includes("PALME D'OR")) return { label: "CANNES", Icon: CannesIcon, weight: 100 };
  if (name.includes("ACADEMY AWARD") || name.includes("OSCAR")) return { label: "ACADEMY AWARDS", Icon: OscarIcon, weight: 100 };
  if (name.includes("GOLDEN GLOBE")) return { label: "GOLDEN GLOBES", Icon: GoldenGlobeIcon, weight: 95 };
  if (name.includes("VENICE") || name.includes("VENEZIA") || name.includes("GOLDEN LION")) return { label: "VENICE", Icon: VeniceIcon, weight: 100 };
  if (name.includes("BERLIN") || name.includes("GOLDEN BEAR")) return { label: "BERLINALE", Icon: BerlinaleIcon, weight: 100 };

  // --- TIER S (Gigantes Internacionais - Peso 90) ---
  if (name.includes("TORONTO") || name.includes("TIFF")) return { label: "TIFF", Icon: TiffIcon, weight: 90 };
  if (name.includes("BAFTA")) return { label: "BAFTA", Icon: BAFTAIcon, weight: 90 };
  if (name.includes("SUNDANCE")) return { label: "SUNDANCE", Icon: SundanceIcon, weight: 90 };
  if (name.includes("LOCARNO")) return { label: "LOCARNO", Icon: LocarnoIcon, weight: 90 };
  if (name.includes("SAN SEBASTIÁN") || name.includes("SAN SEBASTIAN")) return { label: "SAN SEBASTIÁN", Icon: SanSebastianIcon, weight: 90 };
  if (name.includes("KARLOVY VARY") || name.includes("KVIFF")) return { label: "KARLOVY VARY", Icon: KarlovyVaryIcon, weight: 90 };
  if (name.includes("MAR DEL PLATA")) return { label: "MAR DEL PLATA", Icon: GenericLaurelIcon, weight: 90 };

  // --- TIER A (Festivais Cultuados e A-List - Peso 80) ---
  if (name.includes("NEW YORK") || name.includes("NYFF")) return { label: "NEW YORK", Icon: NewYorkFilmFestIcon, weight: 80 };
  if (name.includes("ROTTERDAM") || name.includes("IFFR")) return { label: "IFFR", Icon: RotterdamIcon, weight: 80 };
  if (name.includes("BFI") || name.includes("LONDON")) return { label: "BFI LONDON", Icon: BFILondonIcon, weight: 80 };
  if (name.includes("TELLURIDE")) return { label: "TELLURIDE", Icon: GenericLaurelIcon, weight: 80 };
  if (name.includes("SYDNEY")) return { label: "SYDNEY", Icon: SydneyFilmFestIcon, weight: 80 };
  if (name.includes("ANNECY")) return { label: "ANNECY", Icon: AnnecyIcon, weight: 80 };
  if (name.includes("LA Liff")) return { label: "LA Liff", Icon: LAFilmFestIcon, weight: 80 };


  // --- TIER B (Forte curadoria pop/indie/documentário - Peso 70) ---
  if (name.includes("TRIBECA")) return { label: "TRIBECA", Icon: TribecaIcon, weight: 70 };
  if (name.includes("SXSW") || name.includes("SOUTH BY SOUTHWEST")) return { label: "SXSW", Icon: SXSWIcon, weight: 70 };
  if (name.includes("AFI FEST")) return { label: "AFI FEST", Icon: GenericLaurelIcon, weight: 70 };
  if (name.includes("VISIONS DU RÉEL") || name.includes("VISIONS DU REEL")) return { label: "VISIONS DU RÉEL", Icon: VisionsDuReelIcon, weight: 70 };
  if (name.includes("IL CINEMA RITROVATO") || name.includes("BOLOGNA")) return { label: "IL CINEMA RITROVATO", Icon: CinemaRitrovatoIcon, weight: 70 };
  if (name.includes("VIENNA") || name.includes("VIENNALE")) return { label: "VIENNALE", Icon: ViennaFilmFestIcon, weight: 70 };
  if (name.includes("NEWFEST")) return { label: "NEWFEST", Icon: NewFestIcon, weight: 70 };
  if (name.includes("OPEN CITY")) return { label: "OPEN CITY", Icon: OpenCityIcon, weight: 70 };
  if (name.includes("POLISH SPORTS")) return { label: "POLISH SPORTS FILM", Icon: PolishSportsFilmIcon, weight: 70 };
  if (name.includes("AACTA") || name.includes("AUSTRALIAN ACADEMY")) return { label: "AACTA AWARDS", Icon: AactaIcon, weight: 70 }; 
  if (name.includes("SATURN")) return { label: "SATURN AWARDS", Icon: SaturnIcon, weight: 70 };
  if (name.includes("HUGO")) return { label: "HUGO AWARDS", Icon: HugoIcon, weight: 70 };

  // --- TIER C (Fallback para festivais menores - Peso 10) ---
  // Mantemos um corte de 22 caracteres para o layout não estourar em festivais genéricos
  const safeLabel = name.length > 22 ? name.substring(0, 22) + "..." : name;
  return { label: safeLabel, Icon: GenericLaurelIcon, weight: 10 };
};